import{_ as r,o,c as i,j as t,a as n,t as l,ai as a,ak as c}from"./chunks/framework.SlQmG7ym.js";const b=JSON.parse('{"title":"Features and Mechanics","description":"","frontmatter":{"title":"Features and Mechanics"},"headers":[],"relativePath":"en/usage/features.md","filePath":"en/usage/features.md"}'),u={name:"en/usage/features.md"},d={id:"frontmatter-title",tabindex:"-1"},m={class:"MathJax",jax:"SVG",style:{direction:"ltr",position:"relative"}},h={style:{overflow:"visible","min-height":"1px","min-width":"1px","vertical-align":"-0.566ex"},xmlns:"http://www.w3.org/2000/svg",width:"5.154ex",height:"2.262ex",role:"img",focusable:"false",viewBox:"0 -750 2278 1000","aria-hidden":"true"};function p(s,e,g,T,f,y){return o(),i("div",null,[t("h1",d,[n(l(s.$frontmatter.title)+" ",1),e[0]||(e[0]=t("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":"Permalink to “{{ $frontmatter.title }}”"},"​",-1))]),e[7]||(e[7]=a('<p>After connecting Coyote to experience the &quot;current synergy&quot;, here are a few fun and thrilling core mechanics you can learn about.</p><h2 id="combo-increment" tabindex="-1">Combo Increment <a class="header-anchor" href="#combo-increment" aria-label="Permalink to “Combo Increment”">​</a></h2><p><img src="'+c+'" alt="Combo Increment Diagram"></p><p>To create the ultimate &quot;current synergy high&quot;, the Mod has a built-in <strong>Combo Increment</strong> system.</p><p>When you continuously trigger shocks in a short time (such as sequentially invoking multiple Lightning Orbs), the shock intensity will gradually stack and increment. This multiplier acts on the damage input end. With the compression characteristics of our specially tuned <strong>Stevens&#39;s power law</strong>, it brings a physical sensation of &quot;getting more thrilling as it stacks, but without suddenly maxing out&quot;.</p><ul><li><strong>Increment Ratio Per Stack</strong>: Each stack increases the equivalent damage by <code>15%</code> by default.</li><li><strong>Combo Window</strong>: The time window to maintain the combo, defaulting to <code>3 seconds</code>. If no combo is triggered within the timeout, the state resets.</li><li><strong>Maximum Stack Layers</strong>: Maximum stack defaults to <code>8 layers</code>.</li></ul><h2 id="scientific-current-mapping-algorithm" tabindex="-1">Scientific Current Mapping Algorithm <a class="header-anchor" href="#scientific-current-mapping-algorithm" aria-label="Permalink to “Scientific Current Mapping Algorithm”">​</a></h2><p>Human perception of electrical stimulation is not linear. To perfectly equate the &quot;damage numbers&quot; in the game with the &quot;electrical shock stimulation&quot; your body feels, we introduced the inverse mapping formula of <strong>Stevens&#39;s power law</strong> at the base level.</p>',8)),t("ul",null,[t("li",null,[e[3]||(e[3]=n("The damage calculation will undergo a ",-1)),t("mjx-container",m,[(o(),i("svg",h,[...e[1]||(e[1]=[a('<g stroke="currentColor" fill="currentColor" stroke-width="0" transform="scale(1,-1)"><g data-mml-node="math"><g data-mml-node="mn"><path data-c="31" d="M213 578L200 573Q186 568 160 563T102 556H83V602H102Q149 604 189 617T245 641T273 663Q275 666 285 666Q294 666 302 660V361L303 61Q310 54 315 52T339 48T401 46H427V0H416Q395 3 257 3Q121 3 100 0H88V46H114Q136 46 152 46T177 47T193 50T201 52T207 57T213 61V578Z" style="stroke-width:3;"></path></g><g data-mml-node="TeXAtom" data-mjx-texclass="ORD" transform="translate(500,0)"><g data-mml-node="mo"><path data-c="2F" d="M423 750Q432 750 438 744T444 730Q444 725 271 248T92 -240Q85 -250 75 -250Q68 -250 62 -245T56 -231Q56 -221 230 257T407 740Q411 750 423 750Z" style="stroke-width:3;"></path></g></g><g data-mml-node="mn" transform="translate(1000,0)"><path data-c="33" d="M127 463Q100 463 85 480T69 524Q69 579 117 622T233 665Q268 665 277 664Q351 652 390 611T430 522Q430 470 396 421T302 350L299 348Q299 347 308 345T337 336T375 315Q457 262 457 175Q457 96 395 37T238 -22Q158 -22 100 21T42 130Q42 158 60 175T105 193Q133 193 151 175T169 130Q169 119 166 110T159 94T148 82T136 74T126 70T118 67L114 66Q165 21 238 21Q293 21 321 74Q338 107 338 175V195Q338 290 274 322Q259 328 213 329L171 330L168 332Q166 335 166 348Q166 366 174 366Q202 366 232 371Q266 376 294 413T322 525V533Q322 590 287 612Q265 626 240 626Q208 626 181 615T143 592T132 580H135Q138 579 143 578T153 573T165 566T175 555T183 540T186 520Q186 498 172 481T127 463Z" style="stroke-width:3;"></path><path data-c="2E" d="M78 60Q78 84 95 102T138 120Q162 120 180 104T199 61Q199 36 182 18T139 0T96 17T78 60Z" transform="translate(500,0)" style="stroke-width:3;"></path><path data-c="35" d="M164 157Q164 133 148 117T109 101H102Q148 22 224 22Q294 22 326 82Q345 115 345 210Q345 313 318 349Q292 382 260 382H254Q176 382 136 314Q132 307 129 306T114 304Q97 304 95 310Q93 314 93 485V614Q93 664 98 664Q100 666 102 666Q103 666 123 658T178 642T253 634Q324 634 389 662Q397 666 402 666Q410 666 410 648V635Q328 538 205 538Q174 538 149 544L139 546V374Q158 388 169 396T205 412T256 420Q337 420 393 355T449 201Q449 109 385 44T229 -22Q148 -22 99 32T50 154Q50 178 61 192T84 210T107 214Q132 214 148 197T164 157Z" transform="translate(778,0)" style="stroke-width:3;"></path></g></g></g>',1)])])),e[2]||(e[2]=t("mjx-assistive-mml",{unselectable:"on",display:"inline",style:{top:"0px",left:"0px",clip:"rect(1px, 1px, 1px, 1px)","-webkit-touch-callout":"none","-webkit-user-select":"none","-khtml-user-select":"none","-moz-user-select":"none","-ms-user-select":"none","user-select":"none",position:"absolute",padding:"1px 0px 0px 0px",border:"0px",display:"block",width:"auto",overflow:"hidden"}},[t("math",{xmlns:"http://www.w3.org/1998/Math/MathML"},[t("mn",null,"1"),t("mrow",{"data-mjx-texclass":"ORD"},[t("mo",null,"/")]),t("mn",null,"3.5")])],-1))]),e[4]||(e[4]=n(" power calibration mapping.",-1))]),e[5]||(e[5]=t("li",null,"After amplitude limiting and compression, the specific physical intensity parameters issued are derived.",-1)),e[6]||(e[6]=t("li",null,"This ultimately guarantees a natural transition in intensity, where low damage feels tingly and numb, while high damage provides a stimulating rhythm.",-1))]),e[8]||(e[8]=a('<div class="note custom-block github-alert"><p class="custom-block-title">Tip</p><p>The default algorithm tuning is on the radical side, suitable for thrill-seekers! If you find it a bit too much, you can adjust the &quot;Damage Cap&quot; in the configuration.</p></div><h2 id="one-to-many-connection-multiplayer-fix" tabindex="-1">One-to-Many Connection &amp; Multiplayer Fix <a class="header-anchor" href="#one-to-many-connection-multiplayer-fix" aria-label="Permalink to “One-to-Many Connection &amp; Multiplayer Fix”">​</a></h2><p>Supports simultaneous connection of multiple DG-Lab Coyote 3.0 APPs! Scanning the same QR Code allows your friends to &quot;suffer&quot; along with you.</p><ul><li><strong>Independent Hardware</strong>: Each APP is independently bound to its own Coyote hardware.</li><li><strong>Event Broadcasting</strong>: Shock events are broadcast to all bound clients! <strong>(1 person plays, N people get shocked!)</strong></li><li><strong>Client Management</strong>: When the QR Code panel pops up, you can view all clients and manage them at any time with Kick or Block operations.</li></ul><p>In multiplayer mode, we kept the optional feature where <strong>all Defect players</strong> can trigger the shock. By checking &quot;<strong>Only My Orbs</strong>&quot; in the configuration, your client will only respond to shocks triggered by your own Lightning Orbs, so you won&#39;t be accidentally shocked by your teammates&#39; orbs during multiplayer!</p><h2 id="quick-safe-test-feature" tabindex="-1">Quick Safe Test Feature <a class="header-anchor" href="#quick-safe-test-feature" aria-label="Permalink to “Quick Safe Test Feature”">​</a></h2><p>You no longer need to enter combat and find monsters to get hit just to test the intensity!</p><p>You can set the &quot;<strong>Test Damage</strong>&quot; value in the configuration, and then press the configured &quot;<strong>Test Shock</strong>&quot; hotkey to immediately trigger a shock with this damage value. This makes it convenient for you to repeatedly dial in the most comfortable strength and Waveform in a safe environment.</p><h2 id="known-issues" tabindex="-1">Known Issues <a class="header-anchor" href="#known-issues" aria-label="Permalink to “Known Issues”">​</a></h2><p>The Block function in one-to-many connections is based on the client IP address (session-level, non-persistent). If used behind a reverse proxy/intranet penetration, all clients might share the same IP, meaning blocking one client could accidentally affect others, or the Block might completely fail. This limitation is determined by the DG-LAB WebSocket protocol and cannot be resolved on the Mod side.</p>',10))])}const w=r(u,[["render",p]]);export{b as __pageData,w as default};
